targetCode.css:
body {
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #edf2f0;
}

.product-card {
  width: 320px;
  display: grid;
  gap: 14px;
  border: 1px solid #d7ded9;
  border-radius: 18px;
  background: #fffdf8;
  padding: 24px;
  box-shadow: 0 18px 40px rgba(40, 55, 49, 0.16);
}

.tag {
  width: max-content;
  border-radius: 999px;
  background: #2a9d8f;
  padding: 6px 10px;
  color: white;
  font-size: 0.8rem;
  font-weight: 800;
}

h1 {
  margin: 0;
  color: #17201e;
  font-size: 1.7rem;
}

p {
  margin: 0;
  color: #5b655f;
  line-height: 1.5;
}

strong {
  color: #e76f51;
  font-size: 1.35rem;
}

button {
  border: 0;
  border-radius: 12px;
  background: #17201e;
  padding: 12px 14px;
  color: white;
  font-weight: 800;
}
